import{_ as a,o as e,c as i,ae as t}from"./chunks/framework.BGHOrOyn.js";const c=JSON.parse('{"title":"ROS Wiki","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/ros/init-ros-melodic/ros-wiki.md","filePath":"robotics/ros/init-ros-melodic/ros-wiki.md"}'),n={name:"robotics/ros/init-ros-melodic/ros-wiki.md"};function o(l,s,r,p,u,d){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="ros-wiki" tabindex="-1">ROS Wiki <a class="header-anchor" href="#ros-wiki" aria-label="Permalink to &quot;ROS Wiki&quot;">​</a></h1><h2 id="ubuntu-install-of-ros-melodic" tabindex="-1">Ubuntu install of ROS Melodic <a href="#ubuntu_install_of_ros_melodic" id="ubuntu_install_of_ros_melodic"></a> <a class="header-anchor" href="#ubuntu-install-of-ros-melodic" aria-label="Permalink to &quot;Ubuntu install of ROS Melodic &lt;a href=&quot;#ubuntu_install_of_ros_melodic&quot; id=&quot;ubuntu_install_of_ros_melodic&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>We are building Debian packages for several Ubuntu platforms, listed below. These packages are more efficient than source-based builds and are our preferred installation method for Ubuntu. Note that there are also packages available from Ubuntu upstream. Please see UpstreamPackages to understand the difference.</p><p>Ubuntu packages are built for the following distros and architectures.</p><table tabindex="0"><thead><tr><th>Distro</th><th>amd64</th><th>arm64</th><th>armhf</th></tr></thead><tbody><tr><td>Artful</td><td>X</td><td></td><td></td></tr><tr><td>Bionic</td><td>X</td><td>X</td><td>X</td></tr></tbody></table><p>If you need to install from source (<strong>not recommended</strong>), please see source (download-and-compile) installation instructions.</p><p><strong>If you rely on these packages, please support OSRF.</strong></p><p>These packages are built and hosted on infrastructure maintained and paid for by the <a href="http://www.osrfoundation.org" target="_blank" rel="noreferrer">Open Source Robotics Foundation</a>, a 501(c)(3) non-profit organization. If OSRF were to receive one penny for each downloaded package for just two months, we could cover our annual costs to manage, update, and host all of our online services. Please consider <a href="https://www.openrobotics.org/support-the-ros-buildfarm" target="_blank" rel="noreferrer">donating to OSRF today</a>.</p><p>Contents</p><ol><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Ubuntu install of ROS Melodic</a><ol><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Installation</a><ol><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Configure your Ubuntu repositories</a></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Setup your sources.list</a></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Set up your keys</a></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Installation</a></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Environment setup</a></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Dependencies for building packages</a></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Build farm status</a></li></ol></li><li><a href="./../../../ros/init-ros-melodic/broken-reference/">Tutorials</a></li></ol></li></ol><h3 id="configure-your-ubuntu-repositories" tabindex="-1">Configure your Ubuntu repositories <a href="#installation.2fubuntu.2fsources.configure_your_ubuntu_repositories" id="installation.2fubuntu.2fsources.configure_your_ubuntu_repositories"></a> <a class="header-anchor" href="#configure-your-ubuntu-repositories" aria-label="Permalink to &quot;Configure your Ubuntu repositories &lt;a href=&quot;#installation.2fubuntu.2fsources.configure_your_ubuntu_repositories&quot; id=&quot;installation.2fubuntu.2fsources.configure_your_ubuntu_repositories&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Configure your Ubuntu repositories to allow &quot;restricted,&quot; &quot;universe,&quot; and &quot;multiverse.&quot; You can <a href="https://help.ubuntu.com/community/Repositories/Ubuntu" target="_blank" rel="noreferrer">follow the Ubuntu guide</a> for instructions on doing this.</p><h4 id="setup-your-sources-list" tabindex="-1">Setup your sources.list <a href="#installation.2fubuntu.2fsources.setup_your_sources.list" id="installation.2fubuntu.2fsources.setup_your_sources.list"></a> <a class="header-anchor" href="#setup-your-sources-list" aria-label="Permalink to &quot;Setup your sources.list &lt;a href=&quot;#installation.2fubuntu.2fsources.setup_your_sources.list&quot; id=&quot;installation.2fubuntu.2fsources.setup_your_sources.list&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Setup your computer to accept software from packages.ros.org.</p><ul><li><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo sh -c &#39;echo &quot;deb http://packages.ros.org/ros/ubuntu $(lsb_release -sc) main&quot; &gt; /etc/apt/sources.list.d/ros-latest.list&#39;</span></span></code></pre></div></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>#### Set up your keys &lt;a href=&quot;#installation.2fubuntu.2fsources.set_up_your_keys&quot; id=&quot;installation.2fubuntu.2fsources.set_up_your_keys&quot;&gt;&lt;/a&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>* \`\`\`</span></span>
<span class="line"><span>  sudo apt install curl # if you haven&#39;t already installed curl</span></span>
<span class="line"><span>  curl -s https://raw.githubusercontent.com/ros/rosdistro/master/ros.asc | sudo apt-key add -</span></span></code></pre></div><h4 id="installation" tabindex="-1">Installation <a href="#installation-1" id="installation-1"></a> <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation &lt;a href=&quot;#installation-1&quot; id=&quot;installation-1&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>First, make sure your Debian package index is up-to-date:</p><ul><li><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo apt update</span></span></code></pre></div></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>There are many different libraries and tools in ROS. We provided four default configurations to get you started. You can also install ROS packages individually.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>In case of problems with the next step, you can use following repositories instead of the ones mentioned above [ros-shadow-fixed](http://wiki.ros.org/ShadowRepository)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>*   **Desktop-Full Install: (Recommended)** : ROS, rqt, rviz, robot-generic libraries, 2D/3D simulators and 2D/3D perception</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    *   \`\`\`</span></span>
<span class="line"><span>        sudo apt install ros-melodic-desktop-full</span></span>
<span class="line"><span>        \`\`\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        or [click here](apt:ros-melodic-desktop-full?refresh=yes)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    **Desktop Install:** ROS, rqt, rviz, and robot-generic libraries</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    -   \`\`\`</span></span>
<span class="line"><span>        sudo apt install ros-melodic-desktop</span></span></code></pre></div><pre><code>    or [click here](apt:ros-melodic-desktop?refresh=yes)

**ROS-Base: (Bare Bones)** ROS package, build, and communication libraries. No GUI tools.

*   \`\`\`
    sudo apt install ros-melodic-ros-base
</code></pre><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>        or [click here](apt:ros-melodic-ros-base?refresh=yes)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    **Individual Package:** You can also install a specific ROS package (replace underscores with dashes of the package name):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    -   \`\`\`</span></span>
<span class="line"><span>        sudo apt install ros-melodic-PACKAGE</span></span></code></pre></div><pre><code>    e.g.
</code></pre><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">        sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ros-melodic-slam-gmapping</span></span></code></pre></div><p>To find available packages, use:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ros-melodic</span></span></code></pre></div><h4 id="environment-setup" tabindex="-1">Environment setup <a href="#melodic.2finstallation.2fdebenvironment.environment_setup" id="melodic.2finstallation.2fdebenvironment.environment_setup"></a> <a class="header-anchor" href="#environment-setup" aria-label="Permalink to &quot;Environment setup &lt;a href=&quot;#melodic.2finstallation.2fdebenvironment.environment_setup&quot; id=&quot;melodic.2finstallation.2fdebenvironment.environment_setup&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>It&#39;s convenient if the ROS environment variables are automatically added to your bash session every time a new shell is launched:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;source /opt/ros/melodic/setup.bash&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ~/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bashrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ~/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bashrc</span></span></code></pre></div><p><em>If you have more than one ROS distribution installed, ~/.bashrc must only source the setup.bash for the version you are currently using.</em></p><p>If you just want to change the environment of your current shell, instead of the above you can type:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">opt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ros</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">melodic</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">setup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bash</span></span></code></pre></div><p>If you use zsh instead of bash you need to run the following commands to set up your shell:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;source /opt/ros/melodic/setup.zsh&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span></code></pre></div><h4 id="dependencies-for-building-packages" tabindex="-1">Dependencies for building packages <a href="#installation.2fubuntu.2fbinariesbuilddependencies.dependencies_for_building_packages" id="installation.2fubuntu.2fbinariesbuilddependencies.dependencies_for_building_packages"></a> <a class="header-anchor" href="#dependencies-for-building-packages" aria-label="Permalink to &quot;Dependencies for building packages &lt;a href=&quot;#installation.2fubuntu.2fbinariesbuilddependencies.dependencies_for_building_packages&quot; id=&quot;installation.2fubuntu.2fbinariesbuilddependencies.dependencies_for_building_packages&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Up to now you have installed what you need to run the core ROS packages. To create and manage your own ROS workspaces, there are various tools and requirements that are distributed separately. For example, rosinstall is a frequently used command-line tool that enables you to easily download many source trees for ROS packages with one command.</p><p>To install this tool and other dependencies for building ROS packages, run:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> apt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> python</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rosdep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> python</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rosinstall</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> python</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rosinstall</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">generator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> python</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">wstool</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> build</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">essential</span></span></code></pre></div><p><strong>Initialize rosdep</strong></p><p>Before you can use many ROS tools, you will need to initialize rosdep. rosdep enables you to easily install system dependencies for source you want to compile and is required to run some core components in ROS. If you have not yet installed rosdep, do so as follows.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python-rosdep</span></span></code></pre></div><p>With the following, you can initialize rosdep.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rosdep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rosdep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><h4 id="build-farm-status" tabindex="-1">Build farm status <a href="#build_farm_status" id="build_farm_status"></a> <a class="header-anchor" href="#build-farm-status" aria-label="Permalink to &quot;Build farm status &lt;a href=&quot;#build_farm_status&quot; id=&quot;build_farm_status&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The packages that you installed were built by the <a href="http://build.ros.org" target="_blank" rel="noreferrer">ROS build farm</a>. You can check the status of individual packages <a href="http://repositories.ros.org/status_page/ros_melodic_default.html" target="_blank" rel="noreferrer">here</a>.</p><h3 id="tutorials" tabindex="-1">Tutorials <a href="#melodic.2finstallation.2fpostinstall.tutorials" id="melodic.2finstallation.2fpostinstall.tutorials"></a> <a class="header-anchor" href="#tutorials" aria-label="Permalink to &quot;Tutorials &lt;a href=&quot;#melodic.2finstallation.2fpostinstall.tutorials&quot; id=&quot;melodic.2finstallation.2fpostinstall.tutorials&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>Now, to test your installation, please proceed to the ROS Tutorials.</p><p>Wiki: melodic/Installation/Ubuntu (last edited 2020-03-25 20:11:49 by TullyFoote)</p>`,48)])])}const k=a(n,[["render",o]]);export{c as __pageData,k as default};
